const fs = require('fs');
// ── Machine configuration ──────────────────────────────────────────────────────────────────────────────
// Edit config.json to change paths for your machine. Do not edit this node.
const CONFIG_PATH = process.env.TAROT_CONFIG || 'D:/TarotCardProject/config.json';
// ─────────────────────────────────────────────────────────────────────────────────
const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));

// Read deck-level BaseStyle for the Ollama system prompt
const deck = JSON.parse(fs.readFileSync(config.DefaultDeckJsonPath, 'utf8'));
const musicDefaults = deck.Prompts?.Music || {};

return [{ json: {
    // Machine-specific (from config.json)
    CardsDir:  config.DefaultDeckDir + '/Cards',
    OllamaAPI: config.OllamaAPI,
    // Workflow-specific
    OllamaModel:  'mistral:latest',
    SkipExisting: true,
    // Deck-level music defaults
    BaseStyle:      musicDefaults.BaseStyle || 'ambient orchestral, warm strings, ethereal atmosphere',
    DefaultBPM:     musicDefaults.BPM || 80,
    DefaultKeyScale: musicDefaults.KeyScale || 'D Minor',
} }];

const fs   = require('fs');
const path = require('path');

const params   = $input.first().json;
const cardsDir = params.CardsDir;

const files = fs.readdirSync(cardsDir)
  .filter(f => f.endsWith('.json'))
  .sort();

if (files.length === 0) {
  throw new Error(
    `[Scan Card Files] No JSON files found in ${cardsDir}. ` +
    'Check that CardsDir is correct.'
  );
}

console.log(`[Scan Card Files] Found ${files.length} card files in ${cardsDir}`);

return files.map(f => ({
  json: {
    FilePath:        path.join(cardsDir, f),
    FileName:        f,
    OllamaAPI:       params.OllamaAPI,
    OllamaModel:     params.OllamaModel,
    SkipExisting:    params.SkipExisting,
    BaseStyle:       params.BaseStyle,
    DefaultBPM:      params.DefaultBPM,
    DefaultKeyScale: params.DefaultKeyScale
  }
}));

const http  = require('http');
const https = require('https');
const fs    = require('fs');
const path  = require('path');

// ── HTTP helpers (require('http') instead of axios — see CLAUDE.md) ──
const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):[\/][\/]([^:\/]+)(?::(\d+))?([\/]?[^?]*)(\?.*)?$/);
  if (!m) return reject(new Error('Invalid URL: ' + urlStr));
  const protocol = m[1], hostname = m[2];
  const port = m[3] ? parseInt(m[3]) : (protocol === 'https' ? 443 : 80);
  const reqPath = (m[4] || '/') + (m[5] || '');
  const lib = protocol === 'https' ? https : http;
  const options = { hostname, port, path: reqPath, method, headers: {} };
  if (body) {
    options.headers['Content-Type'] = 'application/json';
    options.headers['Content-Length'] = Buffer.byteLength(body);
  }
  const req = lib.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve(data); } });
  });
  req.on('error', reject);
  req.setTimeout(120000, () => { req.destroy(new Error('Request timeout')); });
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, bodyObj) => httpRequest('POST', url, JSON.stringify(bodyObj));

// ── Main logic ──
const allItems    = $input.all().map(i => i.json);
const ollamaAPI   = allItems[0].OllamaAPI;
const ollamaModel = allItems[0].OllamaModel;
const skipExisting = !!allItems[0].SkipExisting;
const baseStyle   = allItems[0].BaseStyle;

const sleep = ms => new Promise(r => setTimeout(r, ms));
const results = [];
const errors  = [];

// Valid BPM range
const MIN_BPM = 40;
const MAX_BPM = 180;

// System prompt for Ollama
const systemPrompt = [
  'You are a music director for a mystical tarot deck.',
  'The deck\'s base musical style is:',
  `"${baseStyle}"`,
  '',
  'Given a tarot card\'s name, orientation, keywords, and description,',
  'generate ACE-Step music generation tags that are a variation of the',
  'base style, adapted to this card\'s mood and energy.',
  '',
  'Rules:',
  '- Tags must be comma-separated descriptors: genre, instruments, mood, texture',
  '- Always include "instrumental" as a tag',
  '- Keep the Celtic-orchestral foundation but shift instruments/mood to match the card',
  '- BPM range: 50-130 (slow for contemplative cards, faster for action/energy cards)',
  '- KeyScale: choose a key that matches the card\'s emotional tone',
  '  (major keys for positive/bright cards, minor keys for dark/introspective cards)',
  '',
  'Respond with valid JSON only — no markdown, no extra text.',
  'Use exactly these fields:',
  '{',
  '  "Tags": "comma-separated ACE-Step caption tags",',
  '  "BPM": number,',
  '  "KeyScale": "key and scale (e.g. C Major, F# Minor)"',
  '}'
].join('\n');

for (const item of allItems) {
  const { FilePath, FileName } = item;

  // --- Read card JSON ---
  let cardData;
  try {
    cardData = JSON.parse(fs.readFileSync(FilePath, 'utf8'));
  } catch (e) {
    errors.push({ file: FileName, error: 'Read/parse error: ' + e.message });
    console.warn(`[Gen Music] Read error ${FileName}: ${e.message}`);
    continue;
  }

  const cardMeta = cardData['data.Cards'];
  if (!cardMeta || !Array.isArray(cardMeta.records)) {
    errors.push({ file: FileName, error: 'No data.Cards.records array' });
    console.warn(`[Gen Music] No records in ${FileName}`);
    continue;
  }

  const cardName = cardMeta.Card || FileName.replace(/\.json$/, '').replace(/_/g, ' ');
  let updatedCount = 0;

  for (const record of cardMeta.records) {
    const orientation = record.Orientation || '(unknown)';

    // --- Skip if Tags already populated (when SkipExisting=true) ---
    if (skipExisting) {
      const music = record.Prompts?.Music || {};
      if (music.Tags && music.Tags.trim().length > 0) {
        console.log(`[Gen Music] ${cardName}/${orientation}: already has Tags, skipping`);
        continue;
      }
    }

    // --- Gather card context ---
    const keywords = Array.isArray(record.Keywords)
      ? record.Keywords.join(', ')
      : (record.Keywords || '');
    const description = (record.Description || '').substring(0, 250);

    // --- Build user prompt ---
    const userPrompt = [
      `Card: ${cardName}`,
      `Orientation: ${orientation}`,
      `Keywords: ${keywords}`,
      `Description: ${description}`
    ].join('\n');

    // --- Call Ollama ---
    let parsed;
    try {
      const resp = await httpPost(
        ollamaAPI + '/api/generate',
        {
          model:  ollamaModel,
          system: systemPrompt,
          prompt: userPrompt,
          stream: false,
          format: 'json',
          options: { temperature: 0.5, num_predict: 300 }
        }
      );

      const raw = (resp.response || '').trim();
      try {
        parsed = JSON.parse(raw);
      } catch (e) {
        console.warn(`[Gen Music] JSON parse failed for ${cardName}/${orientation}: ${raw.substring(0, 120)}`);
        errors.push({ file: FileName, card: cardName, orientation, error: 'JSON parse: ' + e.message });
        continue;
      }
    } catch (e) {
      console.warn(`[Gen Music] Ollama error for ${cardName}/${orientation}: ${e.message}`);
      errors.push({ file: FileName, card: cardName, orientation, error: 'Ollama: ' + e.message });
      continue;
    }

    // --- Validate Tags ---
    let tags = (parsed.Tags || '').trim();
    if (!tags) {
      console.warn(`[Gen Music] Empty Tags for ${cardName}/${orientation} — skipping`);
      errors.push({ file: FileName, card: cardName, orientation, error: 'Empty Tags from Ollama' });
      continue;
    }
    // Ensure 'instrumental' is in the tags
    if (!tags.toLowerCase().includes('instrumental')) {
      tags = tags + ', instrumental';
    }

    // --- Validate BPM ---
    let bpm = parseInt(parsed.BPM, 10);
    if (isNaN(bpm) || bpm < MIN_BPM || bpm > MAX_BPM) {
      console.warn(`[Gen Music] Invalid BPM ${parsed.BPM} for ${cardName}/${orientation} — using default`);
      bpm = item.DefaultBPM || 80;
    }

    // --- Validate KeyScale ---
    let keyScale = (parsed.KeyScale || '').trim();
    if (!keyScale) {
      keyScale = item.DefaultKeyScale || 'D Minor';
    }

    // --- Merge into record ---
    if (!record.Prompts) record.Prompts = {};
    record.Prompts.Music = {
      Tags:     tags,
      Lyrics:   '[instrumental]',
      BPM:      bpm,
      KeyScale: keyScale
    };

    updatedCount++;
    console.log(`[Gen Music] ${cardName}/${orientation}: Tags="${tags.substring(0, 60)}...", BPM=${bpm}, Key=${keyScale}`);
  }

  // --- Write updated card JSON back to disk ---
  if (updatedCount > 0) {
    try {
      fs.writeFileSync(FilePath, JSON.stringify(cardData, null, 2), 'utf8');
      results.push({ card: cardName, file: FileName, updated: updatedCount });
      console.log(`[Gen Music] Written ${FileName} (${updatedCount} records updated)`);
    } catch (e) {
      errors.push({ file: FileName, card: cardName, error: 'Write error: ' + e.message });
      console.warn(`[Gen Music] Write error ${FileName}: ${e.message}`);
    }
  } else {
    results.push({ card: cardName, file: FileName, updated: 0 });
  }

  // Small delay between cards to avoid overwhelming Ollama
  await sleep(200);
}

if (results.length === 0 && errors.length > 0) {
  throw new Error(
    `[Gen Music] All ${errors.length} cards failed. First: ` +
    `${errors[0].card || errors[0].file} — ${errors[0].error}`
  );
}

if (errors.length > 0) {
  console.warn(`[Gen Music] ${errors.length} record errors across ${results.length} cards`);
}

return [...results, ...errors].map(r => ({ json: r }));

const all       = $input.all().map(i => i.json);
const succeeded = all.filter(j => !j.error && j.updated !== undefined);
const failed    = all.filter(j =>  j.error);

const totalRecords = succeeded.reduce((s, j) => s + (j.updated || 0), 0);

console.log(
  `[Report] Done: ${succeeded.length} cards processed (${totalRecords} records updated), ` +
  `${failed.length} errors`
);

if (failed.length > 0) {
  console.warn('[Report] Errors:');
  for (const f of failed) {
    console.warn(`  ${f.card || f.file}: ${f.error}`);
  }
}

return [{
  json: {
    cardsProcessed:  succeeded.length,
    recordsUpdated:  totalRecords,
    errorCount:      failed.length,
    errors: failed.map(f => ({ card: f.card || f.file, orientation: f.orientation, error: f.error }))
  }
}];
